import json

# Phase 1: Broad scout for any businesses in San Jose, CA, then filter for Indian restaurants
user_question = "San Jose, CA"
scout_result = await delegate_to_scout(task=user_question)
try:
    data = json.loads(scout_result.strip())
    candidates = data.get("candidates", []) or []
except (json.JSONDecodeError, ValueError, AttributeError):
    data, candidates = {}, []
# Filter for Indian restaurants (assuming candidate dict may include a 'cuisine' or 'tags' field)
indian_restaurants = [
    c for c in candidates
    if ("restaurant" in (c.get("category", "").lower() or ""))
    and ("indian" in (c.get("cuisine", "").lower() or c.get("tags", "").lower() or ""))
]
top = indian_restaurants[:3]
enrichments = {}
for i in range(len(top)):
    enrichments[i] = {"candidate": top[i]}
print(f"Scout returned {len(candidates)} total candidates; {len(indian_restaurants)} Indian restaurants, deep-diving top {len(top)}")
